 20→const replaceOrInsert = (html, pattern, replacement) => {
 21→  if (pattern.test(html)) {
 22→    return html.replace(pattern, replacement);
 23→  }
 24→
 25→  return html.replace("</head>", `  ${replacement}\n  </head>`);
 26→};
