 28→const replaceSeo = (html, pathname) => {
 29→  const seo = getSeoForPath(pathname);
 30→  const canonicalUrl = buildAbsoluteUrl(seo.canonicalPath || pathname);
 31→  const ogTitle = seo.ogTitle || seo.title;
 32→  const ogDescription = seo.ogDescription || seo.description;
 33→  const ogImage = seo.ogImage || DEFAULT_OG_IMAGE;
 34→
 35→  let updated = html.replace(/<title>[\s\S]*?<\/title>/i, `<title>${escapeHtml(seo.title)}</title>`);
 36→
 37→  updated = replaceOrInsert(
 38→    updated,
 39→    /<meta[^>]*id=["']seo-description["'][^>]*>/i,
 40→    `<meta id="seo-description" name="description" content="${escapeHtml(seo.description)}" />`
 41→  );
 42→  updated = replaceOrInsert(
 43→    updated,
 44→    /<meta[^>]*id=["']seo-robots["'][^>]*>/i,
 45→    `<meta id="seo-robots" name="robots" content="${escapeHtml(seo.robots || "index,follow")}" />`
 46→  );
 47→  updated = replaceOrInsert(
 48→    updated,
 49→    /<link[^>]*id=["']seo-canonical["'][^>]*>/i,
 50→    `<link id="seo-canonical" rel="canonical" href="${canonicalUrl}" />`
 51→  );
 52→  updated = replaceOrInsert(
 53→    updated,
